const event = $json;

const execution =
  event.execution || {};

const workflow =
  event.workflow || {};

const triggerError =
  event.trigger?.error || {};

const executionError =
  execution.error || {};

const errorMessage =
  String(
    executionError.message ||
    triggerError.message ||
    triggerError.cause?.message ||
    'Unknown workflow error'
  ).trim();

const errorStack =
  String(
    executionError.stack ||
    triggerError.stack ||
    triggerError.cause?.stack ||
    ''
  );

const executionId =
  String(
    execution.id || ''
  ).trim();

const occurredAt =
  new Date().toISOString();

const processingIdMatch =
  errorMessage.match(
    /DOC-[A-Za-z0-9_-]+-\d{2}/
  );

const processingId =
  processingIdMatch?.[0] || '';


let emailMessageId = '';

if (processingId) {
  const processingParts =
    processingId.match(
      /^DOC-(.+)-\d{2}$/
    );

  if (processingParts?.[1]) {
    emailMessageId =
      processingParts[1];
  }
}


const explicitEmailMessageMatch =
  errorMessage.match(
    /email_message_id:\s*([A-Za-z0-9_-]+)/i
  );

const explicitEmailMessageId =
  explicitEmailMessageMatch?.[1] || '';


if (explicitEmailMessageId) {
  emailMessageId =
    explicitEmailMessageId;
}

const workflowId =
  String(
    workflow.id || ''
  ).trim();

const workflowName =
  String(
    workflow.name ||
    'unknown-workflow'
  ).trim();

const lastNode =
  String(
    execution.lastNodeExecuted ||
    triggerError.node?.name ||
    ''
  ).trim();

const executionMode =
  String(
    execution.mode ||
    event.trigger?.mode ||
    ''
  ).trim();

const executionUrl =
  String(
    execution.url || ''
  ).trim();

const criticalWorkflowNames = [
  'invoice__ingestion--gmail',
  'invoice__accounting--google-sheets',
  'invoice__completion--archive',
  'invoice__approval-handler--telegram',
];

const severity =
  criticalWorkflowNames.some(name =>
    workflowName.includes(name)
  )
    ? 'critical'
    : 'error';

const errorIdBase =
  executionId ||
  `${Date.now()}`;

const errorId =
  `ERR-${errorIdBase}`;

return {
  json: {
    error_id:
      errorId,

    occurred_at:
      occurredAt,

    workflow_id:
      workflowId,

    workflow_name:
      workflowName,

    execution_id:
      executionId,

    execution_url:
      executionUrl,

    execution_mode:
      executionMode,

    last_node:
      lastNode,

    error_message:
      errorMessage.slice(0, 2000),

    error_stack:
      errorStack.slice(0, 10000),

    processing_id:
      processingId,

    email_message_id:
      emailMessageId,

    email_message_id_source:
      explicitEmailMessageId
        ? 'error_message'
        : processingId
          ? 'processing_id'
          : 'not_available',

    severity:
      severity,

    error_status:
      'open',

    telegram_alert_required:
      severity === 'critical',

    normalized_at:
      occurredAt,
  },
};

const normalized =
  $('invoice__error--normalize-event').item.json;

const sheetResult =
  $json;

return {
  json: {
    ...normalized,

    processing_log_updated:
      true,

    processing_log_row_number:
      sheetResult.row_number ??
      sheetResult.rowNumber ??
      null,

    processing_log_updated_at:
      new Date().toISOString(),
  },
};

const error = $json;

const escapeHtml = value =>
  String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

const escapeHtmlAttribute = value =>
  escapeHtml(value)
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');

const severity =
  String(error.severity || 'error')
    .trim()
    .toLowerCase();

const severityIcon =
  severity === 'critical'
    ? '🚨'
    : severity === 'warning'
      ? '⚠️'
      : '❌';

const workflowName =
  String(
    error.workflow_name ||
    'Unknown workflow'
  ).trim();

const lastNode =
  String(
    error.last_node ||
    'Unknown node'
  ).trim();

const executionId =
  String(
    error.execution_id ||
    'Unavailable'
  ).trim();

const executionMode =
  String(
    error.execution_mode ||
    'Unknown'
  ).trim();

const errorMessage =
  String(
    error.error_message ||
    'Unknown workflow error'
  )
    .trim()
    .slice(0, 1200);

const occurredAt =
  String(
    error.occurred_at ||
    new Date().toISOString()
  ).trim();

const lines = [
  `${severityIcon} <b>Invoice automation error</b>`,
  '',
  `<b>Severity:</b> ${escapeHtml(severity.toUpperCase())}`,
  `<b>Workflow:</b> ${escapeHtml(workflowName)}`,
  `<b>Node:</b> ${escapeHtml(lastNode)}`,
  `<b>Execution:</b> ${escapeHtml(executionId)}`,
  `<b>Mode:</b> ${escapeHtml(executionMode)}`,
  `<b>Occurred at:</b> ${escapeHtml(occurredAt)}`,
];

if (error.processing_id) {
  lines.push(
    `<b>Processing ID:</b> ${escapeHtml(error.processing_id)}`
  );
}

if (error.email_message_id) {
  lines.push(
    `<b>Gmail Message ID:</b> ${escapeHtml(error.email_message_id)}`
  );
}

if (error.gmail_error_label_added === true) {
  lines.push(
    '<b>Gmail status:</b> AI-Invoices-Error label added'
  );
} else if (error.email_message_id) {
  lines.push(
    '<b>Gmail status:</b> Error label was not added'
  );
} else {
  lines.push(
    '<b>Gmail status:</b> Message ID is unavailable'
  );
}

if (error.processing_log_updated === true) {
  lines.push(
    `<b>Processing log:</b> Updated (${escapeHtml(error.error_id || 'unknown ID')})`
  );
} else {
  lines.push(
    '<b>Processing log:</b> Update not confirmed'
  );
}

lines.push(
  '',
  '<b>Error message:</b>',
  `<code>${escapeHtml(errorMessage)}</code>`
);

if (error.execution_url) {
  const safeExecutionUrl =
    escapeHtmlAttribute(
      String(error.execution_url)
    );

  lines.push(
    '',
    `<a href="${safeExecutionUrl}">Open failed execution</a>`
  );
}

const telegramErrorMessage =
  lines.join('\n');

if (telegramErrorMessage.length > 3900) {
  throw new Error(
    `TELEGRAM_ERROR_MESSAGE_TOO_LONG: ${telegramErrorMessage.length}`
  );
}

return {
  json: {
    ...error,

    telegram_error_message:
      telegramErrorMessage,

    telegram_alert_prepared:
      true,

    telegram_alert_prepared_at:
      new Date().toISOString(),
  },
};

const prepared =
  $('invoice__error--prepare-telegram-alert').item.json;

return {
  json: {
    ...prepared,

    telegram_alert_sent:
      true,

    telegram_alert_sent_at:
      new Date().toISOString(),

    error_handler_completed:
      true,
  },
};

const error =
  $('invoice__error--restore-log-result').item.json;

return {
  json: {
    ...error,

    gmail_error_label_added:
      true,

    gmail_source_label_removed:
      true,

    gmail_error_label_updated_at:
      new Date().toISOString(),
  },
};

return {
  json: {
    ...$json,

    gmail_error_label_added:
      false,

    gmail_source_label_removed:
      false,

    gmail_label_skip_reason:
      'email_message_id_not_available',
  },
};
